label(pic2,"(3)",(0,-9));
label(pic3,"(4)",(0,-9));
label(pic4,"(5)",(0,-9));

add(pic1);
add(shift(20)*pic2);
add(shift(0,-20)*pic3);
add(shift(20,-20)*pic4);
[/asy]

